import androidx.annotation.NonNull;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.text.NumberFormat;
import java.util.Currency;
import java.util.Locale;

public final class MoneyFormatter {
    private MoneyFormatter() {}

    @NonNull
    public static String formatMinor(long minor, @NonNull String currencyCode) {
        Currency c;
        try {
            c = Currency.getInstance(currencyCode);
        } catch (Exception e) {
            c = Currency.getInstance("USD");
        }
        int fraction = c.getDefaultFractionDigits();
        BigDecimal bd = BigDecimal.valueOf(minor).movePointLeft(Math.max(fraction, 0));
        bd = bd.setScale(Math.max(fraction, 0), RoundingMode.HALF_UP);
        NumberFormat nf = NumberFormat.getCurrencyInstance(Locale.getDefault());
        nf.setCurrency(c);
        return nf.format(bd);
    }
}

