package com.example.banking;

import androidx.annotation.NonNull;
import androidx.room.Transaction;

public final class TransactionProcessor {
    private final BankingDatabase db;
    private final AccountRepository accounts;
    private final TransactionRepository transactions;

    public TransactionProcessor(BankingDatabase db,
                                AccountRepository accounts,
                                TransactionRepository transactions) {
        this.db = db;
        this.accounts = accounts;
        this.transactions = transactions;
    }

    @NonNull
    public TransactionResult process(@NonNull TransactionRequest request) {
        if (request.amountMinor <= 0) return TransactionResult.failed("Invalid amount");
        if (request.fromAccountId.equals(request.toAccountId)) return TransactionResult.failed("Accounts must differ");
        if (request.currency.trim().isEmpty()) return TransactionResult.failed("Invalid currency");

        try {
            return db.runInTransaction(() -> processInternal(request));
        } catch (Exception e) {
            return TransactionResult.failed("Processing error");
        }
    }

    @NonNull
    @Transaction
    TransactionResult processInternal(@NonNull TransactionRequest request) {
        TransactionEntity existing = transactions.getById(request.idempotencyKey);
        if (existing != null) return TransactionResult.success(existing.transactionId);

        AccountEntity from = accounts.getById(request.fromAccountId);
        AccountEntity to = accounts.getById(request.toAccountId);

        if (from == null) return TransactionResult.failed("From account not found");
        if (to == null) return TransactionResult.failed("To account not found");
        if (!safeEquals(from.currency, request.currency) || !safeEquals(to.currency, request.currency))
            return TransactionResult.failed("Currency mismatch");
        if (from.balanceMinor < request.amountMinor) return TransactionResult.failed("Insufficient funds");

        long now = System.currentTimeMillis();
        from.balanceMinor = safeSubtract(from.balanceMinor, request.amountMinor);
        to.balanceMinor = safeAdd(to.balanceMinor, request.amountMinor);
        from.updatedAtMs = now;
        to.updatedAtMs = now;

        accounts.upsert(from);
        accounts.upsert(to);

        TransactionEntity tx = new TransactionEntity(
                request.idempotencyKey,
                request.fromAccountId,
                request.toAccountId,
                request.amountMinor,
                request.currency,
                request.description,
                now,
                "SUCCESS"
        );
        transactions.insert(tx);

        return TransactionResult.success(tx.transactionId);
    }

    private static boolean safeEquals(String a, String b) {
        if (a == null) return b == null;
        return a.equals(b);
    }

    private static long safeAdd(long a, long b) {
        long r = a + b;
        if (((a ^ r) & (b ^ r)) < 0) throw new ArithmeticException("overflow");
        return r;
    }

    private static long safeSubtract(long a, long b) {
        long r = a - b;
        if (((a ^ b) & (a ^ r)) < 0) throw new ArithmeticException("overflow");
        return r;
    }
}

