package com.example.banking;

import androidx.annotation.NonNull;
import androidx.lifecycle.LiveData;
import androidx.lifecycle.MutableLiveData;
import androidx.lifecycle.ViewModel;

import java.util.List;

public class BankingViewModel extends ViewModel {
    private final AccountRepository accounts = AppGraph.get().accountRepository;
    private final TransactionRepository transactions = AppGraph.get().transactionRepository;
    private final TransactionProcessor processor = AppGraph.get().transactionProcessor;

    private final MutableLiveData<String> toast = new MutableLiveData<>();
    private final MutableLiveData<Boolean> busy = new MutableLiveData<>(false);

    public LiveData<String> toast() { return toast; }
    public LiveData<Boolean> busy() { return busy; }

    public LiveData<List<AccountEntity>> observeAccounts() {
        return accounts.observeAll();
    }

    public LiveData<AccountEntity> observeAccount(@NonNull String accountId) {
        return accounts.observeById(accountId);
    }

    public LiveData<List<TransactionEntity>> observeTransactionsFor(@NonNull String accountId) {
        return transactions.observeForAccount(accountId);
    }

    public void seedIfEmpty() {
        AppExecutors.io(() -> {
            List<AccountEntity> list = LiveDataUtil.getValueBlocking(accounts.observeAll());
            if (list == null || list.isEmpty()) {
                long now = System.currentTimeMillis();
                accounts.upsert(new AccountEntity("A-1001", "Checking", "USD", 250_00, now));
                accounts.upsert(new AccountEntity("A-2001", "Savings", "USD", 1250_00, now));
            }
        });
    }

    public void transfer(@NonNull String fromId, @NonNull String toId, long amountMinor, @NonNull String currency, String description) {
        busy.postValue(true);
        String idem = Ids.newId();
        TransactionRequest req = new TransactionRequest(fromId, toId, amountMinor, currency, description, idem);
        AppExecutors.io(() -> {
            TransactionResult res = processor.process(req);
            AppExecutors.main(() -> {
                busy.setValue(false);
                if (res.status == TransactionResult.Status.SUCCESS) toast.setValue("Transfer complete");
                else toast.setValue(res.message != null ? res.message : "Transfer failed");
            });
        });
    }
}

package com.example.banking;

import androidx.lifecycle.LiveData;

import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicReference;

public final class LiveDataUtil {
    private LiveDataUtil() {}

    public static <T> T getValueBlocking(LiveData<T> liveData) {
        AtomicReference<T> ref = new AtomicReference<>();
        CountDownLatch latch = new CountDownLatch(1);
        liveData.observeForever(value -> {
            ref.set(value);
            latch.countDown();
        });
        try {
            latch.await(200, TimeUnit.MILLISECONDS);
        } catch (InterruptedException ignored) {
        }
        return ref.get();
    }
}

package com.example.banking;

import android.os.Bundle;
import android.text.Editable;
import android.text.InputFilter;
import android.text.TextWatcher;
import android.view.View;
import android.widget.ArrayAdapter;
import android.widget.Button;
import android.widget.EditText;
import android.widget.ProgressBar;
import android.widget.Spinner;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;
import androidx.lifecycle.ViewModelProvider;

import java.util.ArrayList;
import java.util.List;

public class BankingActivity extends AppCompatActivity {

    private BankingViewModel vm;

    private Spinner fromSpinner;
    private Spinner toSpinner;
    private TextView fromBalance;
    private TextView toBalance;
    private EditText amount;
    private Button transfer;
    private ProgressBar busy;

    private final List<AccountEntity> accountList = new ArrayList<>();
    private ArrayAdapter<String> accountAdapter;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_banking);

        vm = new ViewModelProvider(this).get(BankingViewModel.class);

        fromSpinner = findViewById(R.id.fromSpinner);
        toSpinner = findViewById(R.id.toSpinner);
        fromBalance = findViewById(R.id.fromBalance);
        toBalance = findViewById(R.id.toBalance);
        amount = findViewById(R.id.amount);
        transfer = findViewById(R.id.transferBtn);
        busy = findViewById(R.id.busy);

        amount.setFilters(new InputFilter[]{new InputFilter.LengthFilter(12)});
        amount.addTextChangedListener(new SimpleTextWatcher() {
            @Override public void afterTextChanged(Editable s) { }
        });

        accountAdapter = new ArrayAdapter<>(this, android.R.layout.simple_spinner_item, new ArrayList<>());
        accountAdapter.setDropDownViewResource(android.R.layout.simple_spinner_dropdown_item);
        fromSpinner.setAdapter(accountAdapter);
        toSpinner.setAdapter(accountAdapter);

        vm.toast().observe(this, msg -> {
            if (msg == null) return;
            android.widget.Toast.makeText(this, msg, android.widget.Toast.LENGTH_SHORT).show();
        });

        vm.busy().observe(this, isBusy -> {
            boolean b = isBusy != null && isBusy;
            busy.setVisibility(b ? View.VISIBLE : View.GONE);
            transfer.setEnabled(!b);
        });

        vm.observeAccounts().observe(this, accounts -> {
            accountList.clear();
            accountAdapter.clear();
            if (accounts != null) {
                accountList.addAll(accounts);
                for (AccountEntity a : accounts) {
                    accountAdapter.add(a.displayName + " (" + a.accountId + ")");
                }
            }
            accountAdapter.notifyDataSetChanged();
            updateBalances();
        });

        fromSpinner.setOnItemSelectedListener(new SimpleItemSelectedListener(this::updateBalances));
        toSpinner.setOnItemSelectedListener(new SimpleItemSelectedListener(this::updateBalances));

        transfer.setOnClickListener(v -> doTransfer());

        vm.seedIfEmpty();
    }

    private void updateBalances() {
        AccountEntity from = getSelected(fromSpinner);
        AccountEntity to = getSelected(toSpinner);

        if (from != null) {
            fromBalance.setText(MoneyFormatter.formatMinor(from.balanceMinor, from.currency));
        } else {
            fromBalance.setText("-");
        }

        if (to != null) {
            toBalance.setText(MoneyFormatter.formatMinor(to.balanceMinor, to.currency));
        } else {
            toBalance.setText("-");
        }
    }

    private void doTransfer() {
        AccountEntity from = getSelected(fromSpinner);
        AccountEntity to = getSelected(toSpinner);
        if (from == null || to == null) {
            android.widget.Toast.makeText(this, "Select accounts", android.widget.Toast.LENGTH_SHORT).show();
            return;
        }
        String txt = amount.getText() != null ? amount.getText().toString().trim() : "";
        if (txt.isEmpty()) {
            android.widget.Toast.makeText(this, "Enter amount", android.widget.Toast.LENGTH_SHORT).show();
            return;
        }
        long minor = parseToMinor(txt, from.currency);
        vm.transfer(from.accountId, to.accountId, minor, from.currency, "Transfer");
    }

    private AccountEntity getSelected(Spinner spinner) {
        int pos = spinner.getSelectedItemPosition();
        if (pos < 0 || pos >= accountList.size()) return null;
        return accountList.get(pos);
    }

    private static long parseToMinor(String amountText, String currencyCode) {
        java.util.Currency c;
        try {
            c = java.util.Currency.getInstance(currencyCode);
        } catch (Exception e) {
            c = java.util.Currency.getInstance("USD");
        }
        int fraction = Math.max(0, c.getDefaultFractionDigits());
        java.math.BigDecimal bd = new java.math.BigDecimal(amountText);
        bd = bd.movePointRight(fraction);
        bd = bd.setScale(0, java.math.RoundingMode.HALF_UP);
        return bd.longValueExact();
    }

    private abstract static class SimpleTextWatcher implements TextWatcher {
        @Override public void beforeTextChanged(CharSequence s, int start, int count, int after) {}
        @Override public void onTextChanged(CharSequence s, int start, int before, int count) {}
    }
}

