package com.example.banking;

import android.content.Context;
import android.util.AttributeSet;
import android.widget.LinearLayout;
import android.widget.ProgressBar;
import android.widget.Spinner;
import android.widget.TextView;
import android.widget.Button;
import android.widget.EditText;

public class BankingLayout extends LinearLayout {
    public BankingLayout(Context context) { super(context); init(context); }
    public BankingLayout(Context context, AttributeSet attrs) { super(context, attrs); init(context); }
    public BankingLayout(Context context, AttributeSet attrs, int defStyleAttr) { super(context, attrs, defStyleAttr); init(context); }

    private void init(Context context) {
        setOrientation(VERTICAL);

        Spinner from = new Spinner(context);
        from.setId(R.id.fromSpinner);
        addView(from, new LayoutParams(LayoutParams.MATCH_PARENT, LayoutParams.WRAP_CONTENT));

        TextView fromBal = new TextView(context);
        fromBal.setId(R.id.fromBalance);
        addView(fromBal, new LayoutParams(LayoutParams.MATCH_PARENT, LayoutParams.WRAP_CONTENT));

        Spinner to = new Spinner(context);
        to.setId(R.id.toSpinner);
        addView(to, new LayoutParams(LayoutParams.MATCH_PARENT, LayoutParams.WRAP_CONTENT));

        TextView toBal = new TextView(context);
        toBal.setId(R.id.toBalance);
        addView(toBal, new LayoutParams(LayoutParams.MATCH_PARENT, LayoutParams.WRAP_CONTENT));

        EditText amt = new EditText(context);
        amt.setId(R.id.amount);
        amt.setHint("Amount");
        amt.setInputType(android.text.InputType.TYPE_CLASS_NUMBER | android.text.InputType.TYPE_NUMBER_FLAG_DECIMAL);
        addView(amt, new LayoutParams(LayoutParams.MATCH_PARENT, LayoutParams.WRAP_CONTENT));

        Button btn = new Button(context);
        btn.setId(R.id.transferBtn);
        btn.setText("Transfer");
        addView(btn, new LayoutParams(LayoutParams.MATCH_PARENT, LayoutParams.WRAP_CONTENT));

        ProgressBar pb = new ProgressBar(context);
        pb.setId(R.id.busy);
        pb.setIndeterminate(true);
        pb.setVisibility(GONE);
        addView(pb, new LayoutParams(LayoutParams.WRAP_CONTENT, LayoutParams.WRAP_CONTENT));
    }
}